#!/usr/bin/env node
/**
 * bundle-source.js — Bundle compiler source files into a JS module
 *
 * Reads all source files from src/ that are part of the unity build
 * and outputs demo/compiler-source.js as a self-contained JS object.
 *
 * Usage: node tools/bundle-source.js
 */

var fs = require('fs');
var path = require('path');

var srcDir = path.join(__dirname, '..', 'src');
var outFile = path.join(__dirname, '..', 'demo', 'compiler-source.js');

// Files in the unity build (c2wasm.c #include order), plus c2wasm.c itself.
// file_io.c is excluded — it's a separate native-only compilation unit;
// the WAT codegen generates equivalent WASI helpers automatically.
var files = [
  'c2wasm.c',
  'constants.h',
  'util.c',
  'source.c',
  'lexer.h',
  'lexer.c',
  'types.h',
  'types.c',
  'ast.h',
  'ast.c',
  'parser.h',
  'parser.c',
  'codegen.h',
  'codegen_shared.c',
  'dce.c',
  'bytevec.h',
  'bytevec.c',
  'output.h',
  'output.c',
  'codegen_wat.c',
  'assembler.h',
  'assembler.c',
  'main.c'
];

var out = "'use strict';\n\n";
out += "/**\n";
out += " * Auto-generated by tools/bundle-source.js\n";
out += " * Contains all compiler source files for the live compiler editor.\n";
out += " *\n";
out += " * COMPILER_SOURCE keys are filenames; values are source strings.\n";
out += " * COMPILER_SOURCE_ORDER lists files in unity-build #include order.\n";
out += " */\n\n";

// Build the ordered file list
out += "var COMPILER_SOURCE_ORDER = [\n";
for (var i = 0; i < files.length; i++) {
  out += "  " + JSON.stringify(files[i]);
  if (i < files.length - 1) out += ",";
  out += "\n";
}
out += "];\n\n";

// Build the source object
out += "var COMPILER_SOURCE = {};\n\n";
for (var i = 0; i < files.length; i++) {
  var filePath = path.join(srcDir, files[i]);
  var content = fs.readFileSync(filePath, 'utf8');
  out += "COMPILER_SOURCE[" + JSON.stringify(files[i]) + "] =\n";
  // Split into lines and encode as concatenated string literals
  var lines = content.split('\n');
  for (var j = 0; j < lines.length; j++) {
    var line = lines[j];
    var escaped = JSON.stringify(line + (j < lines.length - 1 ? '\n' : ''));
    if (j === 0) {
      out += "  " + escaped;
    } else {
      out += " +\n  " + escaped;
    }
  }
  out += ";\n\n";
}

fs.writeFileSync(outFile, out);

var totalLines = 0;
for (var i = 0; i < files.length; i++) {
  var content = fs.readFileSync(path.join(srcDir, files[i]), 'utf8');
  totalLines += content.split('\n').length;
}
console.log('Bundled ' + files.length + ' files (' + totalLines + ' lines) -> ' + outFile);
